(5, '73139077', 'DONAYRE MOQUILLAZA', 'CARLOS', '933455159', 'CARLOSDONAYREM0519@GMAIL.COM', '3362', 'SUBTANJALLA', 'SUBTANJALLA', 'ICA', 'Gestión administrativa', 'SE REPORTA EL ERROR EN EL MODULO DE GESTION ADMINISTRATIVA, REALIZANDO LAS PRUEBAS EN CONSULTA EXTERNA-PSICOLOGIA EL DIA 28/08/25, SE PROGRAMA EL TURNO MAÑANA (6 HORAS) PERO NO PERMITE REALIZAR LA PROGRAMACIÓN EL TURNO TARDE (6 HORAS)', 'imagenes/6aa04c53-3c45-4e89-a61b-b337bd0ed893.jpg', 'imagenes/60a49815-8983-406a-abbb-23786a58f0ab.jpg', 'imagenes/4a5377f2-129f-48ba-9600-0c037fe16c6c.jpg', '2025-08-19 17:11:01', '2025-08-20 16:39:45', 'I-3', 'ICA-PALPA-NAZCA', 'SAN JOAQUIN', 'En proceso'),
(6, '40803237', 'AYBAR VALENCIA', 'MARIN', '956287582', 'AYBARVALENCIAMARIN@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Consulta Externa: Medicina', 'BUEN DÍA. RECIBAN UN CORDIAL SALUDO DEL CENTRO DE SALUD DE SUNAMPE.\r\nNOS COMUNICAMOS PARA REPORTAR EL SIGUIENTE INCIDENTE:\r\n\r\nEL MÉDICO GENERÓ LA ATENCIÓN DE UN PACIENTE AL CUAL SE LE EMITIERON DOS REFERENCIAS, REGISTRADAS EN EL APLICATIVO CON LOS NÚMEROS 3420-02402 Y 3420-02401. AMBAS PUDIERON SER DESCARGADAS, SIN EMBARGO, AL MOMENTO DE REALIZAR LA FIRMA SOLO FUE POSIBLE FIRMAR UNA DE ELLAS.\r\n\r\nASIMISMO, AL REVISAR EL DOCUMENTO ELECTRÓNICO EN EL SISTEMA SHICE, ÚNICAMENTE APARECE REGISTRADA UNA DE LAS REFERENCIAS.', 'imagenes/56091b22-98d0-42ef-913f-d4a4043294a5.png', NULL, NULL, '2025-08-20 14:43:15', '2025-08-20 17:15:11', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'En proceso'),
(7, '40803237', 'AYBAR VALENCIA', 'MARIN', '956287582', 'AYBARVALENCIAMARIN@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Consulta Externa: Medicina', 'EL MEDICO HUGO INCHAUSTEGUI,  DNI 70747385 Y SU CORREO ELECTRONICO INCHAUSTEGUI.MEDIC@GMAIL.COM REPORTA QUE NO PUEDE ACCEDER AL SISTEMA, Y ES REITERATIVO.', 'imagenes/9d37413f-7576-4f11-bca3-e82ea8ab0bde.jpg', NULL, NULL, '2025-08-21 17:34:57', '2025-08-21 17:34:57', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'Pendiente'),
(8, '40803237', 'AYBAR VALENCIA', 'MARIN', '956287582', 'AYBARVALENCIAMARIN@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Consulta Externa: Medicina', 'SE HA OBSERVADO EN LA REFERENCIA QUE EL JEFE DEL ESTABLECIMIENTO ES LA ENFERMERA LO CUAL ES CORRECTO, SIN EMBARGO EN LA PARTE INFERIOR APARECE COMO PROFESION MEDICO GENERAL LO CUAL ES INCORRECTO. DEBERIA DE APARECE EL COLEGIO DE ENFERMERAS, TAMPOCO SALE SU NUMERO DE COLEGIATURA. REVISAR POR FAVOR', 'imagenes/7a8ce32e-0d43-4e32-b0dd-c2df4d92809c.png', NULL, NULL, '2025-08-28 14:59:15', '2025-08-28 14:59:15', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'Pendiente'),
(9, '40176162', 'VILLAMARES RAMOS', 'EDWIN JESUS', '957865036', 'EDWINVILLAMARES8212@GMAIL.COM', '3361', 'LA PALMA GRANDE', 'ICA', 'ICA', 'Gestión administrativa', 'EL USUARIO NADIA PACO GOMEZ AL INTENTAR HACER LA FIRMA DEL DOCUMENTO DE ATENCION DE UN PACIENTE DE INMUNIZACIONES LE SALE ESE ERROR.', 'imagenes/1eab0581-1525-43a8-8c7c-c41c6799e320.png', NULL, NULL, '2025-09-11 19:51:42', '2025-09-11 19:51:42', 'I-3', 'ICA-PALPA-NAZCA', 'LA PALMA', 'Pendiente'),
(10, '40176162', 'VILLAMARES RAMOS', 'EDWIN JESUS', '957865036', 'EDWINVILLAMARES8212@GMAIL.COM', '3361', 'LA PALMA GRANDE', 'ICA', 'ICA', 'Gestión administrativa', 'EL APLICATIVO SIHCE AL MOMENTO DE DARLE AL BOTON DE VACUNAS HISMINSA SE QUEDA CARGANDO SIN RESPUESTA , TAMBIEN AL DARLE CLICK AL BOTON DE EDITAR PACIENTE NO EJECUTA Y EL BOTON DE IMPRIMIR SE ENCUENTRA INHABILITADO.', 'imagenes/52ff1a5f-632c-44ae-b179-918029581a36.png', NULL, NULL, '2025-09-11 19:59:08', '2025-09-11 19:59:08', 'I-3', 'ICA-PALPA-NAZCA', 'LA PALMA', 'Pendiente'),
(11, '40803237', 'AYBAR VALENCIA', 'MARIN', '956287582', 'AYBARVALENCIAMARIN@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Consulta Externa: Medicina', 'ESTOY TRATANDO DE REGISTRAR A ESTE PACIENTE PERO EL SISTEMA ME INDICA ESE MENSAJE Y NO PUEDO CONTINUAR', 'imagenes/6470651d-00d2-4e7c-afb2-f00f8095b379.png', NULL, NULL, '2025-09-12 16:25:35', '2025-09-12 16:25:35', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'Pendiente'),
(12, '40803237', 'AYBAR VALENCIA', 'MARIN', '956287582', 'AYBARVALENCIAMARIN@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Consulta Externa: Medicina', 'NUEVAMENTE CON OTRO PACIENTE NO ENCUENTRA DNI', 'imagenes/92dd4098-701b-4851-b3bb-38a185addf98.png', NULL, NULL, '2025-09-13 15:00:52', '2025-09-13 15:00:52', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'Pendiente'),
(13, '40803237', 'AYBAR VALENCIA', 'MARIN', '956287582', 'AYBARVALENCIAMARIN@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Consulta Externa: Medicina', 'PACIENTE MENOR DE EDAD (DNI-90261979) ACUDE ACOMPAÑADO POR SU MADRE Y SE ATIENDE POR CONSULTA EXTERNA, EL MEDICO GENERA LA ATENCION Y SOLICITA EXAMENES DE LABORATORIO AL SOSPECHAR DE APENDICITIS, EL MISMO QUE ES CVONFIRMADO POR LOS EXAMENES DE LABORATORIO, REGISTRA LA ATENCION, L EN SHICE,  PERO SIN EMBARGO NO PERMITE REALIZAR LA REFERENCIA A EMERGENCIA - PEDIATRIA, SOLO PERMITIA REALIZAR LA REFERENCIA A CONSULTA EXTERNA Y HOSPITALIZACION, MAS NO A AMERGENCIA. LA REFERENCIA FINALMENTE SE HIZO POR REFCON.', 'imagenes/ce432110-fe4c-46d4-9b46-fdc1354c9cda.jpg', NULL, NULL, '2025-10-05 00:11:54', '2025-10-05 00:11:54', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'Pendiente'),
(14, '43477817', 'CHAVEZ QUISPE', 'KARLA', '918649465', 'CSSKCHQ@GMAIL.COM', '3420', 'SUNAMPE', 'SUNAMPE', 'CHINCHA', 'Citas', 'AL MOMENTO COLOCAR EL DNI DE LA PACIENTE, NO ENCONTO RESULTADOS PARA PODER OTORGARLE LA CITA A LA PACIENTE PARA LA CONSULTA EXTERNA DE MEDICINA.', 'imagenes/3cfb8da4-aba3-4efe-9b00-89c0bbdf427d.jpg', NULL, NULL, '2025-12-23 15:49:49', '2025-12-23 15:49:49', 'I-3', 'CHINCHA - PISCO', 'CHINCHA', 'Pendiente');
