(2, 2, 22, 'BUEN DíA, NOS REPORTARON PROBLEMAS DE COMUNICACIóN CON LOS SERVICIOS RENIEC. YA ESTá FUNCIONANDO CORRECTAMENTE.', 'Resuelto', NULL, NULL, NULL, '2025-08-14 15:47:42', '2025-08-14 15:47:42'),
(3, 3, 22, 'BUEN DíA,\r\nEL MENSAJE QUE VISUALIZAN SE DEBE A QUE NO ESTá CONFIGURADA LA COLEGIATURA DEL PROFESIONAL EN EL MóDULO DE LOGIN, PUEDEN SOLICITARLO CON EL RESPONSABLE QUE CREA LOS USUARIOS DE LA MICRORED CORRESPONDIENTE. \r\nSALUDOS.', 'Resuelto', 'respuestas/b21e3c69-8872-4347-bf7f-f283cb41c2f3.png', NULL, NULL, '2025-08-18 20:11:57', '2025-08-18 20:11:57'),
(4, 5, 22, 'BUEN DíA, \r\nCOMPARTIR LA CAPTURA DE PANTALLA DE LA CONFIGURACIóN DEL CONSULTORIO DE PSICOLOGíA(INGRESAR EN AMBIENTES Y CONSULTORIOS-> BOTóN CONSULTORIOS), TAMBIéN UNA CAPTURA DE PANTALLA DESDE BANDEJA DE PROGRAMACIONES PARA VISUALIZAR LA DISTRIBUCIóN DE CUPOS DE PSICOLOGíA.', 'En proceso', NULL, NULL, NULL, '2025-08-20 16:43:05', '2025-08-20 16:43:05'),
(5, 6, 22, 'BUEN DíA,\r\nSU TICKET SERá ELEVADO A SOPORTE DE APLICATIVOS DEL MINSA.', 'En proceso', NULL, NULL, NULL, '2025-08-20 17:16:03', '2025-08-20 17:16:03');
